
.status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 24px 4px;
  color: #e0e0e0;
  font-size: 12px;
  flex-shrink: 0;
}

.status-bar-time {
  font-weight: 600;
  letter-spacing: 0.5px;
}

.status-bar-icons {
  display: flex;
  align-items: center;
  gap: 8px;
}

.status-icon {
  width: 16px;
  height: 12px;
  color: #e0e0e0;
}

.battery-icon {
  width: 26px;
  height: 12px;
  color: #4ade80;
}
